let fibonacci = fn(x) {
  if (x == 0) {
    0
  } else {
    if (x == 1) {
      return 1;
    } else {
      fibonacci(x - 1) + fibonacci(x - 2);
    }
  }
};

puts(fibonacci(35));

// `newAdder` returns a closure
let newAdder = fn(a, b) {
    fn(c) { a + b + c };
};

let adder = newAdder(1, 2);

puts(adder(8));

